#include <bits/stdc++.h>
using namespace std;
int l,n,m,d[50004];
bool check(int mid){
	int i=0;
	int sum=0,now=0;
	while(i<=n){
		i++;
		if(d[i]-d[now]<mid)sum++;
		else now=i;
	}
	return sum<=m;
}
int main(){
	cin>>l>>n>>m;
	d[0]=0,d[n+1]=l;
	for(int i=1;i<=n;i++)cin>>d[i];
	if(n==0){
		cout<<l;
		return 0;
	}
	long long ll=1,rr=l;
	while(ll<rr){
		int mid=ll+rr+1>>1;
		if(check(mid))ll=mid;
		else rr=mid-1;
	}
	cout<<ll;
	return 0;
}
